parameters.jsCode:
const t = $('Execute Workflow Trigger').first().json.data;
const mon = $input.first().json;
const satisfied = mon.point_satisfied === true;
const K = Number(t.total_points) || (t.plan ? t.plan.length : 0);
let idx = Number(t.current_point_index) || 1;
let qc = Number(t.point_qcount) || 1;
const CAP = 5;
let done = false;
if (satisfied || qc >= CAP) { idx = idx + 1; qc = 1; if (idx > K) done = true; }
else { qc = qc + 1; }
const target = (!done && t.plan && t.plan[idx-1]) ? t.plan[idx-1] : null;
return [{ json: { done, current_point_index: idx, point_qcount: qc,
  point_satisfied: satisfied, total_points: K, target_point: target } }];

